/**
 * Fontes Barlow / Barlow Condensed (SIL Open Font License 1.1) embutidas em base64
 * para uso no PDF gerado via jsPDF (js/pdf-export.js), sem depender de rede.
 * Fonte: https://github.com/google/fonts/tree/main/ofl/barlow e /ofl/barlowcondensed
 */
const EuGeroPdfFonts = (function () {
  'use strict';

  const BarlowRegular = "";
  const BarlowBold = "";
  const BarlowCondensedRegular = "";
  const BarlowCondensedSemiBold = "";

  function register(doc) {
    doc.addFileToVFS('Barlow-Regular.ttf', BarlowRegular);
    doc.addFont('Barlow-Regular.ttf', 'Barlow', 'normal');
    doc.addFileToVFS('Barlow-Bold.ttf', BarlowBold);
    doc.addFont('Barlow-Bold.ttf', 'Barlow', 'bold');
    doc.addFileToVFS('BarlowCondensed-Regular.ttf', BarlowCondensedRegular);
    doc.addFont('BarlowCondensed-Regular.ttf', 'BarlowCondensed', 'normal');
    doc.addFileToVFS('BarlowCondensed-SemiBold.ttf', BarlowCondensedSemiBold);
    doc.addFont('BarlowCondensed-SemiBold.ttf', 'BarlowCondensed', 'bold');
  }

  return { register };
})();
